// Detect file type and extract account_id from filename or content
const items = $input.all();
const outputs = [];

for (const item of items) {
  const fileName = item.json.fileName || '';
  const isAudio = /\.(m4a|mp3|wav|ogg)$/i.test(fileName);

  // Extract account_id from filename pattern: demo_001.txt → ACC-001
  const numMatch = fileName.match(/(\d{3})/);
  const accountId = numMatch ? `ACC-${numMatch[1]}` : 'ACC-UNKNOWN';

  outputs.push({
    json: {
      file_path: item.json.filePath,
      file_name: fileName,
      account_id: accountId,
      is_audio: isAudio,
      pipeline: 'pipeline_a',
    },
    binary: item.binary,
  });
}

return outputs;

// Parse extraction output and load generated files
const stdout = $json.stdout || '';
const accountId = $json.account_id;
const repoRoot = process.env.REPO_ROOT || '.';
const fs = require('fs');
const path = require('path');

let memo = null;
let spec = null;
let hasError = false;
let errorMsg = '';

try {
  const memoPath = path.join(repoRoot, 'outputs', 'accounts', accountId, 'v1', 'account_memo.json');
  const specPath = path.join(repoRoot, 'outputs', 'accounts', accountId, 'v1', 'retell_agent_spec.json');

  if (fs.existsSync(memoPath)) {
    memo = JSON.parse(fs.readFileSync(memoPath, 'utf8'));
  }
  if (fs.existsSync(specPath)) {
    spec = JSON.parse(fs.readFileSync(specPath, 'utf8'));
  }
} catch (e) {
  hasError = true;
  errorMsg = e.message;
}

return [{
  json: {
    account_id: accountId,
    company_name: memo?.company_name || 'Unknown',
    status: hasError ? 'error' : 'success',
    error: errorMsg,
    memo_version: memo?.version,
    spec_version: spec?.version,
    unknowns: memo?.questions_or_unknowns || [],
    hygiene_pass: spec?.prompt_hygiene_checklist,
    pipeline_stdout: stdout,
  }
}];

// Create tracker task entry
const item = $json;
const repoRoot = process.env.REPO_ROOT || '.';
const { execSync } = require('child_process');

try {
  execSync(
    `cd ${repoRoot} && python3 scripts/tracker.py`,
    { stdio: 'inherit' }
  );
} catch (e) {
  // Non-blocking
}

return [{
  json: {
    ...item,
    task_created: true,
    tracker_path: `${repoRoot}/changelog/tasks.json`,
  }
}];
